/** Lookup map by normalized name for fuzzy matching */
const _nameMap = new Map<string, ProviderUtilization>();
providerUtilizationData.forEach(p => {
  _nameMap.set(p.name.toUpperCase(), p);
});

export function getProviderUtilization(name: string): ProviderUtilization | undefined {
  const upper = name.toUpperCase().trim();
  if (_nameMap.has(upper)) return _nameMap.get(upper);
  // Fuzzy: check if facility name is contained in or contains a utilization name
  for (const [key, val] of _nameMap) {
    if (key.includes(upper) || upper.includes(key)) return val;
  }
  return undefined;
}
